const CartModule = (() => {
  let items = [];
  let total = 0;

  function addItem(product, qty = 1) {
    const existing = items.find(i => i.id === product.id);
    if (existing) {
      existing.qty += qty;
    } else {
      items.push({ id: product.id, name: product.name, price: product.price, qty });
    }
    recalculateTotal();
  }

  function removeItem(productId) {
    items = items.filter(i => i.id !== productId);
    recalculateTotal();
  }

  function recalculateTotal() {
    total = items.reduce((sum, item) => sum + item.price * item.qty, 0);
  }

  function getItems() {
    return [...items];
  }

  function getTotal() {
    return total;
  }

  return {
    addItem,
    removeItem,
    getItems,
    getTotal
  };
})();

export default CartModule;

class EventEmitter {
  constructor() {
    this._events = new Map();
  }

  on(event, listener) {
    if (!this._events.has(event)) {
      this._events.set(event, new Set());
    }
    this._events.get(event).add(listener);
    return () => this.off(event, listener);
  }

  off(event, listener) {
    const listeners = this._events.get(event);
    if (listeners) {
      listeners.delete(listener);
    }
  }

  emit(event, ...args) {
    const listeners = this._events.get(event);
    if (listeners) {
      listeners.forEach(listener => {
        try {
          listener(...args);
        } catch (err) {
          console.error(`Error in event ${event}:`, err);
        }
      });
    }
  }

  once(event, listener) {
    const wrapper = (...args) => {
      this.off(event, wrapper);
      listener(...args);
    };
    return this.on(event, wrapper);
  }
}

module.exports = EventEmitter;

function createUser(id, name, role) {
  let sessions = [];

  const validateSession = (sessionId) => {
    return sessions.includes(sessionId);
  };

  function grantSession(sessionId) {
    if (!sessions.includes(sessionId)) {
      sessions.push(sessionId);
    }
  }

  function revokeSession(sessionId) {
    sessions = sessions.filter(s => s !== sessionId);
  }

  return Object.freeze({
    getId: () => id,
    getName: () => name,
    getRole: () => role,
    grantSession,
    revokeSession,
    validateSession,
    getSessionCount: () => sessions.length,
    toJSON() {
      return { id, name, role, sessionCount: sessions.length };
    }
  });
}

function createAdminUser(id, name, permissions) {
  const user = createUser(id, name, 'admin');
  return Object.setPrototypeOf({ permissions }, user);
}

module.exports = { createUser, createAdminUser };

class MiddlewarePipeline {
  constructor() {
    this.stack = [];
  }

  use(middleware) {
    this.stack.push(middleware);
    return this;
  }

  async execute(context) {
    let index = 0;

    async function next(err) {
      if (err) throw err;
      const middleware = this.stack[index++];
      if (!middleware) return context;
      return middleware(context, next.bind(this));
    }

    return next.call(this);
  }

  async handleRequest(req) {
    const ctx = {
      req,
      res: { status: 200, body: null, headers: {} },
      next
    };

    try {
      await this.execute(ctx);
      return ctx.res;
    } catch (error) {
      return { status: 500, body: { error: error.message } };
    }
  }
}

module.exports = MiddlewarePipeline;

function reactive(target = {}) {
  const handlers = {
    get(obj, prop, receiver) {
      track(obj, prop);
      const value = Reflect.get(obj, prop, receiver);
      return typeof value === 'object' ? reactive(value) : value;
    },

    set(obj, prop, value, receiver) {
      const oldValue = obj[prop];
      const result = Reflect.set(obj, prop, value, receiver);
      if (!Object.is(oldValue, value)) {
        trigger(obj, prop, value, oldValue);
      }
      return result;
    }
  };

  return new Proxy(target, handlers);
}

const deps = new WeakMap();

function track(target, key) {
  const effect = activeEffect;
  if (effect) {
    if (!deps.has(target)) deps.set(target, new Map());
    const map = deps.get(target);
    if (!map.has(key)) map.set(key, new Set());
    map.get(key).add(effect);
  }
}

function trigger(target, key, newValue, oldValue) {
  const map = deps.get(target);
  if (!map) return;
  const effects = map.get(key);
  if (effects) effects.forEach(fn => fn(newValue, oldValue));
}

module.exports = { reactive };

class ConnectionPool {
  static #instance = null;

  constructor(options = {}) {
    if (ConnectionPool.#instance) {
      throw new Error('Use ConnectionPool.getInstance() instead');
    }
    this.maxConnections = options.max || 10;
    this.connections = [];
    this.pendingRequests = [];
    this._initialized = false;
  }

  static getInstance(options) {
    if (!ConnectionPool.#instance) {
      ConnectionPool.#instance = new ConnectionPool(options);
    }
    return ConnectionPool.#instance;
  }

  async acquire() {
    if (this.connections.length > 0) {
      return this.connections.pop();
    }
    if (this.connections.length < this.maxConnections) {
      return this._createConnection();
    }
    return new Promise((resolve) => {
      this.pendingRequests.push(resolve);
    });
  }

  release(connection) {
    this.connections.push(connection);
    const request = this.pendingRequests.shift();
    if (request) request(this.acquire());
  }
}

module.exports = ConnectionPool;

const SortStrategies = {
  ascending: (a, b) => a - b,
  descending: (a, b) => b - a,
  byCreatedAt: (a, b) => new Date(a.createdAt) - new Date(b.createdAt),
  byPriority: (a, b) => b.priority - a.priority,
  custom: (comparator) => comparator
};

class SortEngine {
  constructor(strategy = SortStrategies.ascending) {
    this.strategy = strategy;
  }

  setStrategy(strategy) {
    this.strategy = strategy;
  }

  sort(items) {
    return [...items].sort(this.strategy);
  }

  stableSort(items, keyFn) {
    const wrapped = items.map((item, i) => ({ item, index: i, key: keyFn(item) }));
    wrapped.sort((a, b) => {
      const cmp = this.strategy(a.key, b.key);
      return cmp !== 0 ? cmp : a.index - b.index;
    });
    return wrapped.map(w => w.item);
  }
}

module.exports = { SortStrategies, SortEngine };

const LifecycleMixin = {
  mounted() { this._isMounted = true; },
  unmounted() { this._isMounted = false; }
};

const EventMixin = {
  $on(event, handler) {
    if (!this._handlers) this._handlers = {};
    if (!this._handlers[event]) this._handlers[event] = [];
    this._handlers[event].push(handler);
  },

  $emit(event, ...args) {
    if (this._handlers?.[event]) {
      this._handlers[event].forEach(h => h(...args));
    }
  },

  $off(event, handler) {
    if (handler) {
      this._handlers?.[event]?.splice(
        this._handlers[event].indexOf(handler), 1
      );
    } else {
      delete this._handlers?.[event];
    }
  }
};

const StateMixin = {
  $set(path, value) {
    const keys = path.split('.');
    let target = this;
    for (let i = 0; i < keys.length - 1; i++) {
      target = target[keys[i]] = target[keys[i]] ?? {};
    }
    target[keys.at(-1)] = value;
  }
};

function applyMixins(ctor, mixins) {
  mixins.forEach(m => {
    Object.getOwnPropertyNames(m).forEach(name => {
      if (name !== 'constructor') {
        Object.defineProperty(ctor.prototype, name, Object.getOwnPropertyDescriptor(m, name));
      }
    });
  });
}

module.exports = { LifecycleMixin, EventMixin, StateMixin, applyMixins };
